// Nota ON: C4
msg.topic = "/noteOn";      // <- RUTA OSC (obligatoria)
msg.payload = [60, 100];    // <- args: [note, velocity]
return msg;

// Nota OFF: C4
msg.topic = "/noteOff";
msg.payload = [60];         // <- args: [note]
return msg;

// Nota ON: C#4 (61)
msg.topic = "/noteOn";
msg.payload = [61, 100];   // [nota, velocidad]
return msg;

// Nota OFF: C#4 (61)
msg.topic = "/noteOff";
msg.payload = [61];        // [nota]
return msg;

// ====== CONFIG ======
const LEFT  = "B68";  // mano izquierda
const RIGHT = "A68";  // mano derecha

// STOP: ambas manos z > 1.8 "al mismo tiempo"
const STOP_Z = 1.8;
const SYNC_WINDOW_MS = 120;
const STOP_COOLDOWN_MS = 700;

// Selector instrumento (mano derecha)
const SEL_T = 0.8;

// Disparo escenas (mano izquierda)
const TRIG_T = 1.5;
const HYST   = 0.2;
const TRIG_COOLDOWN_MS = 250;

// Notas base por escena (izquierda)
const BASE_Z = 61; // escena 1
const BASE_Y = 62; // escena 2
const BASE_X = 63; // escena 3

// Nota para "Detener Todo" según tu flow (en tu captura es 60)
const STOP_NOTE = 60;

// ====== STATE ======
let st = context.get("st") || {
  instrument: 1,
  right: { ax:0, ay:0, az:0, t:0 },
  left:  { ax:0, ay:0, az:0, t:0 },
  lastStopAt: 0,
  lastTrigAt: 0,
  armed: { x:true, y:true, z:true }
};

// ====== PARSE INPUT ======
let p = msg.payload;
if (typeof p === "string") {
  try { p = JSON.parse(p); } catch(e) { return null; }
}

const imu = p?.imu;
if (!imu) return null;

const L = imu[LEFT];
const R = imu[RIGHT];
const now = Date.now();

// Si el paquete no trae ambos, igual podemos actualizar lo que venga
if (R && Number.isFinite(R.az) && Number.isFinite(R.ax)) {
  st.right = { ax:Number(R.ax), ay:Number(R.ay), az:Number(R.az), t:now };

  // ====== Instrument selector (RIGHT) ======
  // prioridad: z+, z-, x+, x-
  if (st.right.az >  SEL_T) st.instrument = 1;
  else if (st.right.az < -SEL_T) st.instrument = 2;
  else if (st.right.ax >  SEL_T) st.instrument = 3;
  else if (st.right.ax < -SEL_T) st.instrument = 4;
}

if (L && Number.isFinite(L.az) && Number.isFinite(L.ax) && Number.isFinite(L.ay)) {
  st.left = { ax:Number(L.ax), ay:Number(L.ay), az:Number(L.az), t:now };
}

// ====== STOP GESTURE ======
const freshR = (now - st.right.t) <= SYNC_WINDOW_MS;
const freshL = (now - st.left.t)  <= SYNC_WINDOW_MS;

const stopGesture =
  freshR && freshL &&
  st.right.az > STOP_Z &&
  st.left.az  > STOP_Z;

if (stopGesture && (now - st.lastStopAt) > STOP_COOLDOWN_MS) {
  st.lastStopAt = now;
  context.set("st", st);

  msg.note = STOP_NOTE;
  msg.payload = 1;
  return msg;
}

// ====== Only trigger notes when LEFT is present in this message ======
if (!L) {
  context.set("st", st);
  return null;
}

// ====== Trigger cooldown ======
if ((now - st.lastTrigAt) < TRIG_COOLDOWN_MS) {
  context.set("st", st);
  return null;
}

// ====== Edge detect with hysteresis ======
function edge(name, v) {
  // re-arm when it goes low enough
  if (!st.armed[name] && v < (TRIG_T - HYST)) st.armed[name] = true;

  // fire when armed and crosses threshold
  if (st.armed[name] && v > TRIG_T) {
    st.armed[name] = false;
    return true;
  }
  return false;
}

// Decide scene (priority z > y > x)
let base = null;
if (edge("z", st.left.az)) base = BASE_Z;
else if (edge("y", st.left.ay)) base = BASE_Y;
else if (edge("x", st.left.ax)) base = BASE_X;

if (base === null) {
  context.set("st", st);
  return null;
}

// ====== Compute note ======
// instrument 1 -> +0, instrument 2 -> +3, instrument 3 -> +6, instrument 4 -> +9
const note = base + (st.instrument - 1) * 3;

st.lastTrigAt = now;
context.set("st", st);

// Output "1" to detonate your existing "XX On" function node
msg.note = note;
msg.payload = 1;
return msg;
